/// Internal architecture-snapshot push so the headless watcher can converge
/// the cloud without a tauri command context.
#[allow(clippy::too_many_arguments)]
pub(crate) async fn cloud_mcp_sync_workspace_architectures_internal(
    state: &CloudMcpState,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    graphs: Value,
    reason: Option<String>,
    scope_repo_id: Option<String>,
    scope_git_repo_identity_id: Option<String>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path,
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let mut payload = cloud_mcp_architecture_payload_base(
        &req,
        &workspace_id,
        workspace_name.as_deref(),
        reason.as_deref().unwrap_or("architecture_index_sync"),
    );
    cloud_mcp_apply_architecture_scope(
        &mut payload,
        scope_repo_id.as_deref(),
        scope_git_repo_identity_id.as_deref(),
    );
    let graph_items = cloud_mcp_architecture_graphs_payload(graphs)
        .into_iter()
        .map(cloud_mcp_prepare_architecture_graph)
        .collect::<Vec<_>>();
    if let Some(object) = payload.as_object_mut() {
        object.insert(
            "event_kind".to_string(),
            json!("workspace_architecture_snapshot"),
        );
        object.insert("graphs".to_string(), json!(graph_items.clone()));
        object.insert("architectures".to_string(), json!(graph_items));
        object.insert("content_transport".to_string(), json!("refs"));
        object.insert("contentTransport".to_string(), json!("refs"));
    }
    cloud_mcp_post_event_endpoint(state, "workspace_architecture_snapshot", &payload).await
}

#[tauri::command]
async fn cloud_mcp_sync_workspace_architecture(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: String,
    workspace_name: Option<String>,
    graph: Value,
    reason: Option<String>,
    scope_repo_id: Option<String>,
    scope_git_repo_identity_id: Option<String>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path,
        Some(workspace_id.clone()),
        workspace_name.clone(),
    );
    let mut payload = cloud_mcp_architecture_payload_base(
        &req,
        &workspace_id,
        workspace_name.as_deref(),
        reason.as_deref().unwrap_or("architecture_graph_save"),
    );
    cloud_mcp_apply_architecture_scope(
        &mut payload,
        scope_repo_id.as_deref(),
        scope_git_repo_identity_id.as_deref(),
    );
    let graph = cloud_mcp_prepare_architecture_graph(graph);
    if let Some(object) = payload.as_object_mut() {
        object.insert(
            "event_kind".to_string(),
            json!("workspace_architecture_updated"),
        );
        object.insert("graph".to_string(), graph.clone());
        object.insert("graphs".to_string(), json!([graph.clone()]));
        object.insert("architecture".to_string(), graph.clone());
        object.insert("architectures".to_string(), json!([graph]));
        object.insert("content_transport".to_string(), json!("inline"));
        object.insert("contentTransport".to_string(), json!("inline"));
    }
    cloud_mcp_post_event_endpoint(state.inner(), "workspace_architecture_updated", &payload).await
}

#[tauri::command]
async fn cloud_mcp_hydrate_workspace_architecture(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    refs: Value,
    scope_repo_id: Option<String>,
    scope_git_repo_identity_id: Option<String>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(
        repo_path.clone(),
        workspace_id.clone(),
        workspace_name.clone(),
    );
    let refs_array = cloud_mcp_architecture_refs_array(&refs);
    if refs_array.is_empty() {
        return Ok(json!({
            "kind": "workspace_architecture_hydration",
            "items": [],
            "missing": [],
            "hydratedCount": 0,
            "hydrated_count": 0,
        }));
    }
    let mut payload = cloud_mcp_architecture_payload_base(
        &req,
        workspace_id.as_deref().unwrap_or_default(),
        workspace_name.as_deref(),
        "architecture_content_hydrate",
    );
    cloud_mcp_apply_architecture_scope(
        &mut payload,
        scope_repo_id.as_deref(),
        scope_git_repo_identity_id.as_deref(),
    );
    if let Some(object) = payload.as_object_mut() {
        object.insert("refs".to_string(), json!(refs_array));
    }
    let response = cloud_mcp_post_json_endpoint(
        state.inner(),
        "/v1/workspace/architectures/hydrate",
        &payload,
    )
    .await?;
    let mut data = response.get("data").cloned().unwrap_or(response);
    let hydrated_items = data
        .get("items")
        .or_else(|| data.get("graphs"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default();
    let mut saved_items = Vec::new();
    for item in hydrated_items {
        let Some(graph) = cloud_mcp_architecture_hydrated_graph(item.clone()) else {
            saved_items.push(item);
            continue;
        };
        let repo_for_write = repo_path.clone();
        let saved = tauri::async_runtime::spawn_blocking(move || {
            architecture_graph_write_cloud_arch_blocking(repo_for_write, graph)
        })
        .await
        .map_err(|error| format!("Architecture hydration worker failed: {error}"))??;
        saved_items.push(saved.graph);
    }
    if let Some(object) = data.as_object_mut() {
        let saved_count = saved_items.len();
        object.insert("items".to_string(), json!(saved_items.clone()));
        object.insert("graphs".to_string(), json!(saved_items));
        object.insert("hydrated_count".to_string(), json!(saved_count));
        object.insert("hydratedCount".to_string(), json!(saved_count));
    }
    Ok(data)
}

#[tauri::command]
async fn cloud_mcp_architecture_hub_catalog(
    state: State<'_, CloudMcpState>,
    terminal_state: State<'_, TerminalState>,
    workspaces: Value,
) -> Result<Value, String> {
    let built_at_ms = cloud_mcp_now_ms();
    let global_entry_base =
        tauri::async_runtime::spawn_blocking(architecture_global_root_value)
            .await
            .map_err(|error| format!("Architecture global root worker failed: {error}"))??;
    let global_root_display =
        cloud_mcp_payload_text(&global_entry_base, &["rootDirectory", "root_directory"])
            .unwrap_or_default();
    let global_entry = json!({
        "id": "global-architectures",
        "name": "Global",
        "path": global_root_display,
        "relativePath": ".",
        "hasGit": false,
        "architectureRoot": global_entry_base["architectureRoot"].clone(),
        "graphCount": global_entry_base["graphCount"].clone(),
        "scopeKind": "global",
        "repoId": ARCHITECTURE_GLOBAL_REPO_ID,
        "workspaceId": ARCHITECTURE_GLOBAL_WORKSPACE_ID,
        "workspaceName": "Global",
    });

    let mut covered_identity_keys = HashSet::<String>::new();
    covered_identity_keys.insert(ARCHITECTURE_GLOBAL_REPO_ID.to_string());
    let mut workspace_groups = Vec::new();
    for workspace in workspaces.as_array().cloned().unwrap_or_default() {
        let workspace_id =
            cloud_mcp_payload_text(&workspace, &["workspaceId", "workspace_id", "id"])
                .unwrap_or_default();
        let workspace_name =
            cloud_mcp_payload_text(&workspace, &["workspaceName", "workspace_name", "name"])
                .unwrap_or_default();
        let root_directory = cloud_mcp_payload_text(
            &workspace,
            &["rootDirectory", "root_directory", "repoPath", "repo_path"],
        )
        .unwrap_or_default();
        if workspace_id.is_empty() || root_directory.is_empty() {
            continue;
        }
        let Ok(root) = resolve_workspace_root_directory(Some(root_directory.as_str())) else {
            continue;
        };
        let topology =
            terminal_workspace_topology_scan_for_launch(terminal_state.inner(), &root).await;
        let repositories =
            architecture_repositories_from_mounts(&root, &topology.mounts).repositories;
        let mut repo_entries = Vec::new();
        for repo in repositories {
            let repo_path = PathBuf::from(&repo.path);
            let repo_id = cloud_mcp_repo_id_for_root(&repo_path);
            let identity = cloud_mcp_git_repo_identity_for_path(&repo_path);
            let git_repo_identity_id = cloud_mcp_payload_text(
                &identity,
                &["git_repo_identity_id", "gitRepoIdentityId"],
            )
            .unwrap_or_default();
            covered_identity_keys.insert(repo_id.clone());
            if !git_repo_identity_id.is_empty() {
                covered_identity_keys.insert(git_repo_identity_id.clone());
            }
            // Non-git workspace folders sync under a name-based identity;
            // cover it so they do not duplicate as standalone folder entries.
            let central_identity = architecture_repo_identity_slug(&repo_path);
            if !central_identity.is_empty() {
                covered_identity_keys.insert(central_identity);
            }
            let mut entry = serde_json::to_value(&repo).unwrap_or_else(|_| json!({}));
            if let Some(object) = entry.as_object_mut() {
                object.insert("scopeKind".to_string(), json!("workspace"));
                object.insert("repoId".to_string(), json!(repo_id));
                object.insert(
                    "gitRepoIdentityId".to_string(),
                    json!(git_repo_identity_id),
                );
                object.insert("workspaceId".to_string(), json!(workspace_id.clone()));
                object.insert("workspaceName".to_string(), json!(workspace_name.clone()));
            }
            repo_entries.push(entry);
        }
        workspace_groups.push(json!({
            "workspaceId": workspace_id,
            "workspaceName": workspace_name,
            "rootDirectory": workspace_path_display(&root),
            "repositories": repo_entries,
        }));
    }

    let account_list = {
        let device_profile = cloud_mcp_desktop_device_profile();
        let payload = json!({
            "source": "rust-diffforge-architecture",
            "reason": "architecture_hub_catalog",
            "scope": "account",
            "device": device_profile.clone(),
            "device_id": device_profile["device_id"].clone(),
            "deviceId": device_profile["device_id"].clone(),
            "ts_ms": cloud_mcp_now_ms(),
        });
        cloud_mcp_post_json_endpoint(state.inner(), "/v1/workspace/architectures/list", &payload)
            .await
            .map(|response| response.get("data").cloned().unwrap_or(response))
            .ok()
    };
    let mut cloud_error = String::new();
    if account_list.is_none() {
        cloud_error = "Cloud architecture index is unavailable; showing local repos only.".to_string();
    }
    // Locally known central-store entries (named folders, agent-made folders,
    // previously synced repos) show up even before any cloud round-trip.
    let mut extra_entries = BTreeMap::<String, Value>::new();
    let local_central_entries =
        tauri::async_runtime::spawn_blocking(architecture_central_store_entries)
            .await
            .map_err(|error| format!("Architecture central store worker failed: {error}"))?
            .unwrap_or_default();
    for entry in local_central_entries {
        let identity_key = cloud_mcp_payload_text(&entry, &["identityKey", "repoId"])
            .unwrap_or_default();
        if identity_key.is_empty() || covered_identity_keys.contains(&identity_key) {
            continue;
        }
        extra_entries.insert(identity_key, entry);
    }

    let mut orphan_groups = BTreeMap::<String, Vec<Value>>::new();
    if let Some(account_list) = &account_list {
        for row in account_list
            .get("graphs")
            .or_else(|| account_list.get("architectures"))
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default()
        {
            let identity_key = cloud_mcp_payload_text(&row, &["identity_key", "identityKey"])
                .or_else(|| cloud_mcp_payload_text(&row, &["repo_id", "repoId"]))
                .unwrap_or_default();
            if identity_key.is_empty() || covered_identity_keys.contains(&identity_key) {
                continue;
            }
            orphan_groups.entry(identity_key).or_default().push(row);
        }
    }
    for (identity_key, rows) in orphan_groups {
        let first = rows.first().cloned().unwrap_or_else(|| json!({}));
        let cloud_name = cloud_mcp_payload_text(
            &first,
            &[
                "git_repo_display_name",
                "gitRepoDisplayName",
                "workspace_name",
                "workspaceName",
            ],
        )
        .or_else(|| {
            cloud_mcp_payload_text(&first, &["workspace_root", "workspaceRoot"]).and_then(
                |root| {
                    root.replace('\\', "/")
                        .split('/')
                        .filter(|part| !part.is_empty())
                        .next_back()
                        .map(str::to_string)
                },
            )
        });
        if let Some(existing) = extra_entries.get_mut(&identity_key) {
            // The folder already exists locally; cloud rows only improve the
            // display name for entries that had to fall back to their slug.
            if let Some(object) = existing.as_object_mut() {
                let is_named_folder = object["scopeKind"].as_str() == Some("folder");
                if !is_named_folder {
                    if let Some(name) = cloud_name {
                        object.insert("name".to_string(), json!(name));
                    }
                }
            }
            continue;
        }
        let orphan_identity = identity_key.clone();
        let orphan_root = tauri::async_runtime::spawn_blocking(move || {
            architecture_orphan_root_dir(&orphan_identity)
        })
        .await
        .map_err(|error| format!("Architecture orphan root worker failed: {error}"))??;
        let is_named_folder = identity_key.starts_with("folder-");
        let name = if is_named_folder {
            cloud_name.unwrap_or_else(|| {
                identity_key
                    .trim_start_matches("folder-")
                    .replace('-', " ")
            })
        } else {
            cloud_name.unwrap_or_else(|| identity_key.clone())
        };
        extra_entries.insert(identity_key.clone(), json!({
            "id": format!("orphan-{identity_key}"),
            "name": name,
            "path": workspace_path_display(&orphan_root),
            "relativePath": ".",
            "hasGit": false,
            "architectureRoot": workspace_path_display(&orphan_root.join(".agents").join("architectures")),
            "graphCount": rows.len(),
            "scopeKind": if is_named_folder { "folder" } else { "orphan" },
            "repoId": cloud_mcp_payload_text(&first, &["repo_id", "repoId"]).unwrap_or_else(|| identity_key.clone()),
            "gitRepoIdentityId": cloud_mcp_payload_text(&first, &["git_repo_identity_id", "gitRepoIdentityId"]).unwrap_or_default(),
            "identityKey": identity_key,
            "workspaceId": cloud_mcp_payload_text(&first, &["workspace_id", "workspaceId"]).unwrap_or_default(),
            "workspaceName": cloud_mcp_payload_text(&first, &["workspace_name", "workspaceName"]).unwrap_or_default(),
        }));
    }

    let mut folder_entries = Vec::new();
    let mut orphan_entries = Vec::new();
    for (_, entry) in extra_entries {
        if entry["scopeKind"].as_str() == Some("folder") {
            folder_entries.push(entry);
        } else {
            orphan_entries.push(entry);
        }
    }

    Ok(json!({
        "kind": "architecture_hub_catalog",
        "version": 1,
        "builtAtMs": built_at_ms,
        "global": global_entry,
        "workspaces": workspace_groups,
        "folderRepositories": folder_entries,
        "orphanRepositories": orphan_entries,
        "cloudIndexAvailable": account_list.is_some(),
        "cloudError": cloud_error,
        "globalRepoId": ARCHITECTURE_GLOBAL_REPO_ID,
        "globalWorkspaceId": ARCHITECTURE_GLOBAL_WORKSPACE_ID,
    }))
}

fn cloud_mcp_asset_payload_base(
    req: &CloudMcpRepoRequest,
    workspace_id: &str,
    workspace_name: Option<&str>,
    reason: &str,
) -> Value {
    let device_profile = cloud_mcp_desktop_device_profile();
    json!({
        "source": "rust-diffforge-assets",
        "reason": reason,
        "repo_id": req.repo_id,
        "repoId": req.repo_id,
        "repo_path": req.root_display,
        "repoPath": req.root_display,
        "workspace_root": req.root_display,
        "workspaceRoot": req.root_display,
        "workspace_id": workspace_id,
        "workspaceId": workspace_id,
        "workspace_name": workspace_name.unwrap_or_default(),
        "workspaceName": workspace_name.unwrap_or_default(),
        "device": device_profile.clone(),
        "device_id": device_profile["device_id"].clone(),
        "deviceId": device_profile["device_id"].clone(),
        "machine_id": device_profile["device_id"].clone(),
        "machineId": device_profile["device_id"].clone(),
        "device_name": device_profile["device_name"].clone(),
        "machine_name": device_profile["machine_name"].clone(),
        "ts_ms": cloud_mcp_now_ms(),
    })
}

fn cloud_mcp_file_sha256_and_size(path: &Path) -> Result<(String, u64), String> {
    let mut file = fs::File::open(path)
        .map_err(|error| format!("Unable to open asset file {}: {error}", path.display()))?;
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 128 * 1024];
    let mut size = 0u64;
    loop {
        let read = file
            .read(&mut buffer)
            .map_err(|error| format!("Unable to read asset file {}: {error}", path.display()))?;
        if read == 0 {
            break;
        }
        size = size.saturating_add(read as u64);
        hasher.update(&buffer[..read]);
    }
    Ok((format!("{:x}", hasher.finalize()), size))
}

fn cloud_mcp_asset_kind_for_mime(mime: &str) -> &'static str {
    if mime.starts_with("image/") {
        "image"
    } else if mime.starts_with("video/") {
        "video"
    } else if mime.starts_with("audio/") {
        "audio"
    } else if mime == "application/pdf" {
        "pdf"
    } else if mime.contains("zip") || mime.contains("tar") || mime.contains("compressed") {
        "archive"
    } else {
        "file"
    }
}

fn cloud_mcp_asset_mime_for_path(path: &Path) -> String {
    match path
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or_default()
        .to_ascii_lowercase()
        .as_str()
    {
        "png" => "image/png",
        "jpg" | "jpeg" => "image/jpeg",
        "gif" => "image/gif",
        "webp" => "image/webp",
        "svg" => "image/svg+xml",
        "mp4" => "video/mp4",
        "mov" => "video/quicktime",
        "mp3" => "audio/mpeg",
        "wav" => "audio/wav",
        "pdf" => "application/pdf",
        "zip" => "application/zip",
        "tar" => "application/x-tar",
        "gz" => "application/gzip",
        "json" => "application/json",
        "txt" | "md" => "text/plain",
        _ => "application/octet-stream",
    }
    .to_string()
}

fn cloud_mcp_asset_extension_for_mime(mime: &str) -> Option<&'static str> {
    match mime.trim().to_ascii_lowercase().as_str() {
        "image/png" => Some("png"),
        "image/jpeg" | "image/jpg" => Some("jpg"),
        "image/gif" => Some("gif"),
        "image/webp" => Some("webp"),
        "image/svg+xml" => Some("svg"),
        "video/mp4" => Some("mp4"),
        "video/quicktime" => Some("mov"),
        "audio/mpeg" => Some("mp3"),
        "audio/wav" | "audio/wave" => Some("wav"),
        "application/pdf" => Some("pdf"),
        "application/zip" => Some("zip"),
        "application/json" => Some("json"),
        "text/plain" => Some("txt"),
        _ => None,
    }
}

fn cloud_mcp_sanitize_asset_filename(name: &str, fallback: &str) -> String {
    let leaf = name
        .rsplit(['/', '\\'])
        .next()
        .unwrap_or_default()
        .trim();
    let mut sanitized = leaf
        .chars()
        .map(|character| match character {
            '\0'..='\u{1f}' | '\u{7f}' => '_',
            '<' | '>' | ':' | '"' | '/' | '\\' | '|' | '?' | '*' => '_',
            _ => character,
        })
        .collect::<String>()
        .trim_matches([' ', '.'])
        .to_string();
    if sanitized.is_empty() || sanitized == "." || sanitized == ".." {
        sanitized = fallback.trim().to_string();
    }
    if sanitized.is_empty() {
        sanitized = "asset".to_string();
    }
    let stem = sanitized
        .split('.')
        .next()
        .unwrap_or_default()
        .to_ascii_uppercase();
    let reserved = matches!(
        stem.as_str(),
        "CON"
            | "PRN"
            | "AUX"
            | "NUL"
            | "COM1"
            | "COM2"
            | "COM3"
            | "COM4"
            | "COM5"
            | "COM6"
            | "COM7"
            | "COM8"
            | "COM9"
            | "LPT1"
            | "LPT2"
            | "LPT3"
            | "LPT4"
            | "LPT5"
            | "LPT6"
            | "LPT7"
            | "LPT8"
            | "LPT9"
    );
    if reserved {
        sanitized.insert(0, '_');
    }
    const MAX_ASSET_FILENAME_CHARS: usize = 180;
    if sanitized.chars().count() > MAX_ASSET_FILENAME_CHARS {
        let path = Path::new(&sanitized);
        let extension = path
            .extension()
            .and_then(|value| value.to_str())
            .filter(|value| !value.is_empty())
            .map(|value| format!(".{value}"))
            .unwrap_or_default();
        let extension_chars = extension.chars().count();
        let keep = MAX_ASSET_FILENAME_CHARS
            .saturating_sub(extension_chars)
            .max(24);
        let stem = path
            .file_stem()
            .and_then(|value| value.to_str())
            .unwrap_or("asset")
            .chars()
            .take(keep)
            .collect::<String>();
        sanitized = format!("{stem}{extension}");
    }
    sanitized
}

fn cloud_mcp_sanitize_asset_id(value: &str) -> String {
    let sanitized = value
        .trim()
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() || matches!(character, '-' | '_' | '.') {
                character
            } else {
                '-'
            }
        })
        .collect::<String>()
        .trim_matches(['-', '.', '_'])
        .to_string();
    if sanitized.is_empty() {
        format!("asset-{}", uuid::Uuid::new_v4())
    } else {
        sanitized
    }
}

fn cloud_mcp_managed_asset_root() -> Result<PathBuf, String> {
    cloud_mcp_local_data_file_path(CLOUD_MCP_MANAGED_ASSET_ROOT_DIR)
        .ok_or_else(|| "Managed asset root is unavailable.".to_string())
}

fn cloud_mcp_asset_extension_hint(input: &Value) -> Option<String> {
    cloud_mcp_payload_text(input, &["extension", "ext"])
        .map(|value| {
            value
                .trim()
                .trim_start_matches('.')
                .chars()
                .filter(|character| character.is_ascii_alphanumeric())
                .collect::<String>()
                .to_ascii_lowercase()
        })
        .filter(|value| !value.is_empty())
        .or_else(|| {
            cloud_mcp_payload_text(input, &["mime_type", "mimeType"])
                .and_then(|mime| cloud_mcp_asset_extension_for_mime(&mime).map(str::to_string))
        })
}

fn cloud_mcp_asset_filename_for_input(input: &Value, fallback: &str) -> String {
    let raw_name = cloud_mcp_payload_text(input, &["name", "filename", "file_name", "fileName"])
        .unwrap_or_else(|| fallback.to_string());
    let mut filename = cloud_mcp_sanitize_asset_filename(&raw_name, fallback);
    if Path::new(&filename).extension().is_none() {
        if let Some(extension) = cloud_mcp_asset_extension_hint(input) {
            filename = format!("{filename}.{extension}");
        }
    }
    filename
}

fn cloud_mcp_available_asset_download_path(target_dir: &Path, filename: &str) -> PathBuf {
    let candidate = target_dir.join(filename);
    if !candidate.exists() {
        return candidate;
    }
    let path = Path::new(filename);
    let stem = path.file_stem().and_then(|value| value.to_str()).unwrap_or("asset");
    let extension = path
        .extension()
        .and_then(|value| value.to_str())
        .filter(|value| !value.is_empty())
        .map(|value| format!(".{value}"))
        .unwrap_or_default();
    for index in 1..10_000 {
        let next = target_dir.join(format!("{stem} ({index}){extension}"));
        if !next.exists() {
            return next;
        }
    }
    target_dir.join(format!(
        "{}-{}{}",
        stem,
        cloud_mcp_now_ms(),
        extension
    ))
}

fn cloud_mcp_promote_generated_asset_to_library(
    repo_path: Option<&str>,
    workspace_id: Option<&str>,
    source_path: &Path,
    name_hint: Option<&str>,
    prompt: Option<&str>,
) -> Result<Value, String> {
    let source_path = source_path
        .canonicalize()
        .unwrap_or_else(|_| source_path.to_path_buf());
    if !source_path.is_file() {
        return Err(format!(
            "Generated image asset does not exist: {}",
            source_path.display()
        ));
    }

    let mime_type = cloud_mcp_asset_mime_for_path(&source_path);
    if !mime_type.starts_with("image/") {
        return Err(format!(
            "Generated asset is not an image: {}",
            source_path.display()
        ));
    }

    let (source_sha256, source_size_bytes) = cloud_mcp_file_sha256_and_size(&source_path)?;
    let req = cloud_mcp_repo_request(
        repo_path.unwrap_or_default().to_string(),
        workspace_id.map(str::to_string),
        None,
    );
    let workspace_id_text = workspace_id.unwrap_or_default();
    let asset_id = format!(
        "asset-imagegen-{}",
        cloud_mcp_short_hash(&format!(
            "{}:{}:{}:{}",
            req.repo_id, workspace_id_text, source_sha256, source_size_bytes
        ))
    );

    let fallback_name = source_path
        .file_name()
        .and_then(|value| value.to_str())
        .filter(|value| !value.trim().is_empty())
        .unwrap_or("generated-image");
    let mut filename = cloud_mcp_sanitize_asset_filename(
        name_hint
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or(fallback_name),
        "generated-image",
    );
    if Path::new(&filename).extension().is_none() {
        if let Some(extension) = cloud_mcp_asset_extension_for_mime(&mime_type) {
            filename = format!("{filename}.{extension}");
        }
    }

    let asset_root = cloud_mcp_managed_asset_root()?;
    let target_dir = asset_root.join("imagegen").join(&asset_id);
    fs::create_dir_all(&target_dir).map_err(|error| {
        format!(
            "Unable to create generated image asset directory {}: {error}",
            target_dir.display()
        )
    })?;
    let target_path = target_dir.join(&filename);
    let should_copy = match cloud_mcp_file_sha256_and_size(&target_path) {
        Ok((target_sha256, target_size_bytes)) => {
            target_sha256 != source_sha256 || target_size_bytes != source_size_bytes
        }
        Err(_) => true,
    };
    if should_copy {
        fs::copy(&source_path, &target_path).map_err(|error| {
            format!(
                "Unable to copy generated image asset {} to {}: {error}",
                source_path.display(),
                target_path.display()
            )
        })?;
    }
    let target_path = target_path
        .canonicalize()
        .unwrap_or_else(|_| target_path.to_path_buf());
    let target_path_text = target_path.display().to_string();

    if let Ok(existing) = cloud_mcp_asset_row_from_file(&asset_id) {
        let existing_path = cloud_mcp_asset_row_text(&existing, &["local_path", "localPath", "path"]);
        if existing_path == target_path_text && Path::new(&existing_path).is_file() {
            return Ok(json!({
                "kind": "generated_asset_promoted",
                "source": "managed_asset_library",
                "asset_id": asset_id,
                "assetId": asset_id,
                "local_path": target_path_text,
                "localPath": target_path_text,
                "path": target_path_text,
                "asset": existing,
            }));
        }
    }

    let metadata = json!({
        "source": "codex_imagegen_autocopy",
        "sourceKind": "imagegen",
        "original_path": source_path.display().to_string(),
        "originalPath": source_path.display().to_string(),
        "prompt": prompt.unwrap_or_default(),
    });
    let input = json!({
        "asset_id": asset_id,
        "assetId": asset_id,
        "name": filename,
        "filename": filename,
        "mime_type": mime_type,
        "mimeType": mime_type,
        "kind": "image",
        "source_kind": "imagegen",
        "sourceKind": "imagegen",
        "metadata": metadata,
    });
    let row = cloud_mcp_asset_local_row_with_input(
        &req,
        workspace_id_text,
        req.workspace_name.as_deref(),
        &target_path,
        &input,
    )?;
    cloud_mcp_asset_store_local_row(&row)?;

    Ok(json!({
        "kind": "generated_asset_promoted",
        "source": "managed_asset_library",
        "asset_id": asset_id,
        "assetId": asset_id,
        "local_path": target_path_text,
        "localPath": target_path_text,
        "path": target_path_text,
        "asset": row,
    }))
}

fn cloud_mcp_asset_local_row(
    req: &CloudMcpRepoRequest,
    workspace_id: &str,
    workspace_name: Option<&str>,
    path: &Path,
    metadata: Option<Value>,
) -> Result<Value, String> {
    let canonical = path.canonicalize().unwrap_or_else(|_| path.to_path_buf());
    let (sha256, size_bytes) = cloud_mcp_file_sha256_and_size(&canonical)?;
    let mime_type = cloud_mcp_asset_mime_for_path(&canonical);
    let name = canonical
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or("asset")
        .to_string();
    let asset_id = format!(
        "asset-{}",
        cloud_mcp_short_hash(&format!(
            "{}:{}:{}:{}",
            workspace_id,
            canonical.display(),
            sha256,
            size_bytes
        ))
    );
    Ok(json!({
        "id": asset_id,
        "asset_id": asset_id,
        "assetId": asset_id,
        "repo_id": req.repo_id,
        "repoId": req.repo_id,
        "workspace_id": workspace_id,
        "workspaceId": workspace_id,
        "workspace_name": workspace_name.unwrap_or_default(),
        "workspaceName": workspace_name.unwrap_or_default(),
        "name": name,
        "filename": name,
        "kind": cloud_mcp_asset_kind_for_mime(&mime_type),
        "mime_type": mime_type,
        "mimeType": mime_type,
        "size_bytes": size_bytes,
        "sizeBytes": size_bytes,
        "sha256": sha256,
        "cloud_status": "local_only",
        "cloudStatus": "local_only",
        "local_status": "local_available",
        "localStatus": "local_available",
        "local_path": canonical.display().to_string(),
        "localPath": canonical.display().to_string(),
        "path": canonical.display().to_string(),
        "metadata": metadata.unwrap_or_else(|| json!({})),
        "created_at": cloud_mcp_rfc3339_now(),
        "createdAt": cloud_mcp_rfc3339_now(),
        "updated_at": cloud_mcp_rfc3339_now(),
        "updatedAt": cloud_mcp_rfc3339_now(),
    }))
}

fn cloud_mcp_asset_local_row_with_input(
    req: &CloudMcpRepoRequest,
    workspace_id: &str,
    workspace_name: Option<&str>,
    path: &Path,
    input: &Value,
) -> Result<Value, String> {
    let mut row = cloud_mcp_asset_local_row(
        req,
        workspace_id,
        workspace_name,
        path,
        input.get("metadata").cloned(),
    )?;
    if let Some(object) = row.as_object_mut() {
        if let Some(asset_id) = cloud_mcp_payload_text(input, &["asset_id", "assetId", "id"]) {
            let asset_id = cloud_mcp_sanitize_asset_id(&asset_id);
            object.insert("id".to_string(), json!(asset_id));
            object.insert("asset_id".to_string(), json!(asset_id));
            object.insert("assetId".to_string(), json!(asset_id));
        }
        if let Some(name) = cloud_mcp_payload_text(input, &["name", "filename", "file_name", "fileName"])
        {
            let name = cloud_mcp_sanitize_asset_filename(&name, "asset");
            object.insert("name".to_string(), json!(name));
            object.insert("filename".to_string(), json!(name));
        }
        if let Some(mime_type) = cloud_mcp_payload_text(input, &["mime_type", "mimeType"]) {
            object.insert("mime_type".to_string(), json!(mime_type.clone()));
            object.insert("mimeType".to_string(), json!(mime_type.clone()));
            object.insert(
                "kind".to_string(),
                json!(cloud_mcp_asset_kind_for_mime(&mime_type)),
            );
        }
        if let Some(kind) = cloud_mcp_payload_text(input, &["kind", "asset_kind", "assetKind"]) {
            object.insert("kind".to_string(), json!(kind));
        }
        let source_kind = cloud_mcp_payload_text(input, &["source_kind", "sourceKind", "source"])
            .unwrap_or_else(|| "asset_library".to_string());
        object.insert("source_kind".to_string(), json!(source_kind.clone()));
        object.insert("sourceKind".to_string(), json!(source_kind));
        object.insert("asset_scope".to_string(), json!("account"));
        object.insert("assetScope".to_string(), json!("account"));
    }
    Ok(row)
}

fn cloud_mcp_rfc3339_now() -> String {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| format!("{}.{:03}Z", duration.as_secs(), duration.subsec_millis()))
        .unwrap_or_else(|_| "0.000Z".to_string())
}

fn cloud_mcp_asset_store_local_row(row: &Value) -> Result<(), String> {
    let conn = cloud_mcp_open_asset_library_conn()?;
    cloud_mcp_update_asset_library_conn(
        &conn,
        "local_asset_registration",
        Some(cloud_mcp_base_url().as_str()),
        cloud_mcp_payload_text(row, &["repo_id", "repoId"]).as_deref(),
        cloud_mcp_payload_text(row, &["workspace_id", "workspaceId"]).as_deref(),
        &json!({"items": [row.clone()]}),
    )
}

fn cloud_mcp_asset_row_from_file(asset_id: &str) -> Result<Value, String> {
    let conn = cloud_mcp_open_asset_library_conn()?;
    cloud_mcp_asset_library_init_conn(&conn)
        .map_err(|error| format!("Unable to initialize asset cache: {error}"))?;
    let text: String = conn
        .query_row(
            "SELECT row_json FROM workspace_asset_items WHERE asset_id=?1",
            rusqlite::params![asset_id],
            |row| row.get(0),
        )
        .map_err(|error| format!("Asset {asset_id} is not registered locally: {error}"))?;
    serde_json::from_str::<Value>(&text)
        .map_err(|error| format!("Local asset row for {asset_id} is invalid: {error}"))
}

fn cloud_mcp_asset_replace_local_row(asset_id: &str, row: &Value) -> Result<(), String> {
    let conn = cloud_mcp_open_asset_library_conn()?;
    cloud_mcp_asset_library_init_conn(&conn)
        .map_err(|error| format!("Unable to initialize asset cache: {error}"))?;
    let updated = conn
        .execute(
            "UPDATE workspace_asset_items
             SET repo_id=?1,
                 workspace_id=?2,
                 workspace_name=?3,
                 name=?4,
                 kind=?5,
                 mime_type=?6,
                 size_bytes=?7,
                 sha256=?8,
                 blob_id=?9,
                 cloud_status=?10,
                 local_status=?11,
                 local_path=?12,
                 object_key=?13,
                 origin_device_id=?14,
                 updated_at=?15,
                 mirror_updated_at_ms=?16,
                 row_json=?17
             WHERE asset_id=?18",
            rusqlite::params![
                cloud_mcp_asset_row_text(row, &["repo_id", "repoId"]),
                cloud_mcp_asset_row_text(row, &["workspace_id", "workspaceId"]),
                cloud_mcp_asset_row_text(row, &["workspace_name", "workspaceName"]),
                cloud_mcp_asset_row_text(row, &["name", "filename", "file_name", "fileName"]),
                cloud_mcp_asset_row_text(row, &["kind", "asset_kind", "assetKind"]),
                cloud_mcp_asset_row_text(row, &["mime_type", "mimeType"]),
                cloud_mcp_asset_row_i64(row, &["size_bytes", "sizeBytes"]),
                cloud_mcp_asset_row_text(row, &["sha256"]),
                cloud_mcp_asset_row_text(row, &["blob_id", "blobId"]),
                cloud_mcp_asset_row_text(row, &["cloud_status", "cloudStatus", "status"]),
                cloud_mcp_asset_row_text(row, &["local_status", "localStatus"]),
                cloud_mcp_asset_row_text(row, &["local_path", "localPath", "path"]),
                cloud_mcp_asset_row_text(row, &["object_key", "objectKey"]),
                cloud_mcp_asset_row_text(row, &["origin_device_id", "originDeviceId", "device_id", "deviceId"]),
                cloud_mcp_asset_row_text(row, &["updated_at", "updatedAt"]),
                cloud_mcp_now_ms() as i64,
                row.to_string(),
                asset_id,
            ],
        )
        .map_err(|error| format!("Unable to update local asset row {asset_id}: {error}"))?;
    if updated == 0 {
        return Err(format!("Asset {asset_id} is not registered locally."));
    }
    Ok(())
}

fn cloud_mcp_delete_local_asset_copy(asset_id: &str, delete_file: bool) -> Result<Value, String> {
    let mut row = cloud_mcp_asset_row_from_file(asset_id)?;
    let local_path = cloud_mcp_payload_text(&row, &["local_path", "localPath", "path"])
        .unwrap_or_default();
    let mut removed_file = false;
    if delete_file && !local_path.is_empty() {
        let path = PathBuf::from(&local_path);
        if path.exists() {
            fs::remove_file(&path).map_err(|error| {
                format!("Unable to delete local asset file {}: {error}", path.display())
            })?;
            removed_file = true;
        }
    }
    let now = cloud_mcp_rfc3339_now();
    let cloud_status = cloud_mcp_payload_text(&row, &["cloud_status", "cloudStatus", "status"])
        .unwrap_or_default();
    if let Some(object) = row.as_object_mut() {
        if !local_path.is_empty() {
            object.insert("local_path_hint".to_string(), json!(local_path.clone()));
            object.insert("localPathHint".to_string(), json!(local_path.clone()));
            object.insert("last_local_path".to_string(), json!(local_path.clone()));
            object.insert("lastLocalPath".to_string(), json!(local_path.clone()));
        }
        object.insert("local_path".to_string(), json!(""));
        object.insert("localPath".to_string(), json!(""));
        object.insert("path".to_string(), json!(""));
        object.insert("local_status".to_string(), json!("local_deleted"));
        object.insert("localStatus".to_string(), json!("local_deleted"));
        object.insert("local_available".to_string(), json!(false));
        object.insert("localAvailable".to_string(), json!(false));
        object.insert("local_deleted_at".to_string(), json!(now.clone()));
        object.insert("localDeletedAt".to_string(), json!(now.clone()));
        object.insert("updated_at".to_string(), json!(now.clone()));
        object.insert("updatedAt".to_string(), json!(now.clone()));
        object.insert("can_upload".to_string(), json!(false));
        object.insert("canUpload".to_string(), json!(false));
        object.insert(
            "can_download".to_string(),
            json!(matches!(
                cloud_status.as_str(),
                "cloud_available" | "complete" | "completed" | "uploaded" | "ready"
            )),
        );
        object.insert(
            "canDownload".to_string(),
            json!(matches!(
                cloud_status.as_str(),
                "cloud_available" | "complete" | "completed" | "uploaded" | "ready"
            )),
        );
    }
    cloud_mcp_asset_replace_local_row(asset_id, &row)?;
    Ok(json!({
        "kind": "workspace_asset_local_deleted",
        "source": "local_asset_library",
        "asset_id": asset_id,
        "assetId": asset_id,
        "local_path": local_path,
        "localPath": local_path,
        "file_removed": removed_file,
        "fileRemoved": removed_file,
        "asset": row.clone(),
        "assets": [row],
    }))
}

fn cloud_mcp_asset_http_headers(
    token: Option<&str>,
    repo_id: &str,
    workspace_id: &str,
    route_token: Option<&str>,
) -> Result<reqwest::header::HeaderMap, String> {
    let mut headers = reqwest::header::HeaderMap::new();
    if let Some(token) = token {
        headers.insert(
            reqwest::header::AUTHORIZATION,
            reqwest::header::HeaderValue::from_str(&format!("Bearer {token}"))
                .map_err(|error| format!("Invalid asset transfer auth header: {error}"))?,
        );
    }
    headers.insert(
        "x-diffforge-client-id",
        reqwest::header::HeaderValue::from_static(CLOUD_MCP_RUST_CLIENT_ID),
    );
    headers.insert(
        "x-diffforge-actor",
        reqwest::header::HeaderValue::from_static(CLOUD_MCP_RUST_CLIENT_ID),
    );
    headers.insert(
        "x-diffforge-repo-id",
        reqwest::header::HeaderValue::from_str(repo_id)
            .map_err(|error| format!("Invalid asset transfer repo header: {error}"))?,
    );
    headers.insert(
        "x-diffforge-workspace-id",
        reqwest::header::HeaderValue::from_str(workspace_id)
            .map_err(|error| format!("Invalid asset transfer workspace header: {error}"))?,
    );
    let device_profile = cloud_mcp_desktop_device_profile();
    if let Some(device_id) = cloud_mcp_payload_text(&device_profile, &["device_id", "deviceId"]) {
        headers.insert(
            "x-diffforge-device-id",
            reqwest::header::HeaderValue::from_str(&device_id)
                .map_err(|error| format!("Invalid asset transfer device header: {error}"))?,
        );
    }
    let (billing_scope_type, team_id) = cloud_mcp_process_account_scope();
    headers.insert(
        "x-diffforge-billing-scope-type",
        reqwest::header::HeaderValue::from_str(&billing_scope_type)
            .map_err(|error| format!("Invalid asset transfer scope header: {error}"))?,
    );
    if let Some(team_id) = team_id {
        headers.insert(
            "x-diffforge-team-id",
            reqwest::header::HeaderValue::from_str(&team_id)
                .map_err(|error| format!("Invalid asset transfer team header: {error}"))?,
        );
    }
    if let Some(route_token) = route_token.filter(|value| !value.trim().is_empty()) {
        headers.insert(
            "x-diffforge-direct-route-token",
            reqwest::header::HeaderValue::from_str(route_token)
                .map_err(|error| format!("Invalid asset transfer route header: {error}"))?,
        );
    }
    Ok(headers)
}

#[tauri::command]
async fn cloud_mcp_list_workspace_assets(
    state: State<'_, CloudMcpState>,
    repo_path: String,
    workspace_id: Option<String>,
    workspace_name: Option<String>,
    limit: Option<u64>,
    include_all_workspaces: Option<bool>,
    local_only: Option<bool>,
) -> Result<Value, String> {
    let req = cloud_mcp_repo_request(repo_path, workspace_id.clone(), workspace_name.clone());
    // Assets are account-global; per-workspace filtering is opt-in.
    let include_all_workspaces = include_all_workspaces.unwrap_or(true);
    let effective_limit = limit
        .unwrap_or(100)
        .clamp(1, CLOUD_MCP_ASSET_LIBRARY_MAX_ROWS as u64);
    let local_repo_id = if include_all_workspaces {
        None
    } else {
        Some(req.repo_id.as_str())
    };
    let local_workspace_id = if include_all_workspaces {
        None
    } else {
        workspace_id.as_deref()
    };
    let local = cloud_mcp_asset_library_from_file(
        local_repo_id,
        local_workspace_id,
        effective_limit as usize,
    );
    if local_only.unwrap_or(false) {
        return Ok(local);
    }
    let mut payload = cloud_mcp_asset_payload_base(
        &req,
        workspace_id.as_deref().unwrap_or_default(),
        workspace_name.as_deref(),
        "asset_library_list",
    );
    if let Some(object) = payload.as_object_mut() {
        object.insert(
            "include_all_workspaces".to_string(),
            json!(include_all_workspaces),
        );
        object.insert(
            "includeAllWorkspaces".to_string(),
            json!(include_all_workspaces),
        );
        object.insert("limit".to_string(), json!(effective_limit));
    }
    match cloud_mcp_post_json_endpoint(state.inner(), "/v1/workspace/assets/list", &payload).await {
        Ok(response) => {
            let remote = response.get("data").cloned().unwrap_or(response);
            Ok(cloud_mcp_asset_library_merge_local(remote, local))
        }
        Err(_) => Ok(local),
    }
}

